command:
const tableName = "Dungeon Setup Table";

const descriptions = {
  "Cache (Loot)": "A room whose primary purpose is to reward exploration with treasure, supplies, equipment, or useful resources.",

  "Sidekick": "A room containing an ally, prisoner, guide, or temporary companion who can assist the party.",

  "Offshoot": "An optional path or side area that is not required to complete the dungeon but offers additional risk, discovery, or reward.",

  "Foreshadowing": "A room or feature that hints at future dangers, enemies, themes, or events deeper in the dungeon.",

  "History": "A room that reveals lore, background information, or the story of the dungeon and its inhabitants.",

  "Oddity": "A strange, memorable, or unique feature that exists simply because the dungeon is an unusual place. It may not have an obvious purpose.",

  "Forge": "A location where characters can create, improve, repair, enchant, or otherwise modify equipment and resources.",

  "Factions": "A room showcasing groups with goals, conflicts, or alliances that can create social encounters and dynamic situations.",

  "Map": "A room that points toward future adventures, hidden locations, secret passages, or other places worth exploring.",

  "Puzzle": "An obstacle that blocks progress and requires observation, experimentation, problem-solving, or interaction to overcome."
};

const table = game.tables.getName(tableName);

if (!table) {
  ui.notifications.error(`RollTable "${tableName}" not found.`);
  return;
}

const roll = await new Roll("1d10").evaluate();

const draw = await table.draw({
  roll,
  displayChat: false
});

const result = draw.results[0];

const description = descriptions[result.text] || "No description found.";

let content = `
<h2>🏰 Dungeon Room Feature</h2>

<p><strong>Roll:</strong> ${roll.total}</p>

<p>
<strong>Room Type:</strong>
[${result.range[0]}] ${result.text}
</p>

<p>
<strong>Description:</strong><br>
${description}
</p>

<hr>

<p><em>Use this as the primary feature of the room.</em></p>
`;

ChatMessage.create({
  user: game.user.id,
  speaker: ChatMessage.getSpeaker(),
  content
});
